import './App.css';

function App() {
  const [menu, setMenu] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeCategory, setActiveCategory] = useState('all');
  const [contactForm, setContactForm] = useState({ name: '', email: '', message: '' });
  const [contactSubmitted, setContactSubmitted] = useState(false);
  const [restaurantInfo, setRestaurantInfo] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [menuResponse, aboutResponse] = await Promise.all([
        fetch('/api/menu'),
        fetch('/api/about')
      ]);

      if (!menuResponse.ok || !aboutResponse.ok) {
        throw new Error('Failed to fetch data');
      }

      const menuData = await menuResponse.json();
      const aboutData = await aboutResponse.json();

      setMenu(menuData.data);
      setRestaurantInfo(aboutData.data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('/api/contact', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(contactForm),
      });

      if (response.ok) {
        setContactSubmitted(true);
        setContactForm({ name: '', email: '', message: '' });
        setTimeout(() => setContactSubmitted(false), 3000);
      }
    } catch (err) {
      console.error('Error submitting contact form:', err);
    }
  };

  const categories = ['all', 'appetizer', 'pizza', 'pasta', 'main', 'salad', 'dessert'];
  const filteredMenu = activeCategory === 'all' 
    ? menu 
    : menu.filter(item => item.category === activeCategory);

  const categoryNames = {
    all: 'All Items',
    appetizer: 'Appetizers',
    pizza: 'Pizzas',
    pasta: 'Pasta',
    main: 'Main Courses',
    salad: 'Salads',
    dessert: 'Desserts'
  };

  return (
    <div className="min-h-screen bg-light">
      {/* Navigation */}
      <nav className="bg-dark text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center">
              <h1 className="text-2xl font-bold text-primary">Luigi's Italian Kitchen</h1>
            </div>
            <div className="hidden md:block">
              <div className="ml-10 flex items-baseline space-x-4">
                <a href="#menu" className="hover:bg-gray-700 px-3 py-2 rounded-md">Menu</a>
                <a href="#about" className="hover:bg-gray-700 px-3 py-2 rounded-md">About</a>
                <a href="#contact" className="hover:bg-gray-700 px-3 py-2 rounded-md">Contact</a>
              </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="bg-gradient-to-r from-primary to-secondary text-white py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-5xl md:text-6xl font-bold mb-6">Authentic Italian Cuisine</h1>
          <p className="text-xl md:text-2xl mb-8 opacity-90">
            Experience the taste of Italy with our traditional recipes passed down through generations
          </p>
          <a href="#menu" className="bg-white text-primary px-8 py-3 rounded-full font-semibold hover:bg-gray-100 transition-colors inline-block">
            View Our Menu
          </a>
        </div>
      </section>

      {/* Menu Section */}
      <section id="menu" className="py-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <h2 className="text-4xl font-bold text-center text-dark mb-12">Our Menu</h2>

          {/* Category Filter */}
          <div className="flex flex-wrap justify-center gap-2 mb-8">
            {categories.map(category => (
              <button
                key={category}
                onClick={() => setActiveCategory(category)}
                className={`px-4 py-2 rounded-full font-medium transition-colors ${
                  activeCategory === category
                    ? 'bg-primary text-white'
                    : 'bg-gray-200 text-dark hover:bg-gray-300'
                }`}
              >
                {categoryNames[category]}
              </button>
            ))}
          </div>

          {/* Menu Items */}
          {loading ? (
            <div className="text-center py-12">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto"></div>
              <p className="mt-4 text-dark">Loading menu...</p>
            </div>
          ) : error ? (
            <div className="text-center py-12">
              <p className="text-red-600">Error: {error}</p>
              <button
                onClick={fetchData}
                className="mt-4 bg-primary text-white px-4 py-2 rounded-lg hover:bg-red-700"
              >
                Retry
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredMenu.map(item => (
                <div key={item.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-xl transition-shadow">
                  <div className="h-48 bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center">
                    <span className="text-6xl">🍕</span>
                  </div>
                  <div className="p-6">
                    <h3 className="text-xl font-bold text-dark mb-2">{item.name}</h3>
                    <p className="text-gray-600 mb-4">{item.description}</p>
                    <div className="flex justify-between items-center">
                      <span className="text-2xl font-bold text-primary">${item.price.toFixed(2)}</span>
                      <button className="bg-secondary text-white px-4 py-2 rounded-lg hover:bg-purple-700 transition-colors">
                        Order Now
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* About Section */}
      <section id="about" className="py-16 bg-dark text-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid md:grid-cols-2 gap-12 items-center">
            <div>
              <h2 className="text-4xl font-bold mb-6">About Luigi's Italian Kitchen</h2>
              <p className="text-lg text-gray-300 mb-6">
                {restaurantInfo?.description}
              </p>
              <div className="space-y-4">
                <p><strong>📍 Address:</strong> {restaurantInfo?.address}</p>
                <p><strong>📞 Phone:</strong> {restaurantInfo?.phone}</p>
                <p><strong>🕐 Hours:</strong> {restaurantInfo?.hours}</p>
                <p><strong>📧 Email:</strong> {restaurantInfo?.email}</p>
              </div>
            </div>
            <div className="bg-gradient-to-br from-primary to-secondary rounded-lg p-8 text-center">
              <div className="text-8xl mb-4">🍝</div>
              <p className="text-xl">Family Owned & Operated Since 1985</p>
            </div>
          </div>
        </div>
      </section>

      {/* Contact Section */}
      <section id="contact" className="py-16">
        <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
          <h2 className="text-4xl font-bold text-center text-dark mb-8">Contact Us</h2>

          {contactSubmitted && (
            <div className="bg-green-100 border border-green-400 text-green-700 px-4 py-3 rounded-lg mb-6 text-center">
              Thank you! Your message has been received.
            </div>
          )}

          <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-md p-8">
            <div className="mb-6">
              <label className="block text-dark font-medium mb-2">Name</label>
              <input
                type="text"
                required
                value={contactForm.name}
                onChange={(e) => setContactForm({ ...contactForm, name: e.target.value })}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent"
                placeholder="Your name"
              />
            </div>
            <div className="mb-6">
              <label className="block text-dark font-medium mb-2">Email</label>
              <input
                type="email"
                required
                value={contactForm.email}
                onChange={(e) => setContactForm({ ...contactForm, email: e.target.value })}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent"
                placeholder="your@email.com"
              />
            </div>
            <div className="mb-6">
              <label className="block text-dark font-medium mb-2">Message</label>
              <textarea
                required
                rows={4}
                value={contactForm.message}
                onChange={(e) => setContactForm({ ...contactForm, message: e.target.value })}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent"
                placeholder="Your message..."
              />
            </div>
            <button
              type="submit"
              className="w-full bg-primary text-white py-3 rounded-lg font-semibold hover:bg-red-700 transition-colors"
            >
              Send Message
            </button>
          </form>
        </div>
      </section>

      {/* Footer */}
      <footer className="bg-dark text-white py-8">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <p className="text-gray-400">© 2024 Luigi's Italian Kitchen. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
}

export default App;
